-- Build-Up Sprint / Stride-Out (build-up-sprint-stride-out)
UPDATE coaching.exercise SET
  name = 'Build-Up Sprint / Stride-Out',
  description = 'Athlete starts from a rolling, two-point, or three-point entry and builds speed progressively through the first half of the rep, then holds max-effort upright mechanics through the stride-out zone. Decelerate under control after the prescribed distance.',
  card_summary = 'Gradual acceleration to upright max-effort stride-out over 20–40 yards — the primary Output entry to upright speed before flying sprints.',
  coach_language = 'Use as the safest Output max-velocity primer — teaches rhythm into top speed without a sudden fly-in. Stop when posture, arm action, or decel quality drops.',
  athlete_language = 'Build smooth, then open it up — tall, quick feet, strike under you, and finish the rep in control.',
  movement_family = 'Max-velocity exposure',
  primary_phase_key = 'output',
  phase_subrole = 'max_velocity_exposure',
  primary_order_slot = 'sprint_exposure',
  default_sets = 1,
  default_reps = 3,
  default_work_seconds = NULL,
  default_rest_seconds = 90,
  est_seconds_per_set = 45,
  movement_requirements = '{"primary_joint_actions":["hip_extension","knee_extension","ankle_plantarflexion"],"primary_tissues":["hamstrings","glutes","calves"],"breathing_demand":"nasal","balance_demand":"dynamic","impact_level":4,"prerequisites":["a-march","a-skip"]}'::jsonb,
  coaching_execution = '{"movement_description":"Progressive build to upright max-effort stride-out over 20–40 yards, then controlled deceleration.","setup":["Mark 20–40 yard lane with cones or line tape.","Confirm athlete is fresh — no heavy legs or prior max sprint block.","Choose start type (rolling, two-point, or three-point) based on training age.","Define deceleration zone beyond finish cones."],"execution_steps":["Set start with tall posture and clear intent cue.","Accelerate smoothly — do not pop vertical on first steps.","Transition to upright max-effort stride-out through the back half of the rep.","Maintain tall posture, quick ground contacts, and coordinated arm drive.","Decelerate progressively after the finish mark; walk back for full rest."],"breathing_cues":["Relaxed face at the line.","Exhale through the build; stay loose through shoulders."],"coach_cues":["Build, then open.","Tall through the top.","Strike under the hip.","Do not chase volume — chase one clean rep.","Decel under control."],"athlete_cues":["Smooth build.","Open it up.","Stay tall.","Quick feet.","Finish in control."],"common_faults":["Sprinting max from step one instead of building.","Overstriding once upright.","Posture collapsing or sitting back at max speed.","Running past prescribed distance for extra volume.","Poor deceleration or abrupt stop at end of rep."],"stop_signs":["Hamstring tightness or pull sensation.","Velocity clearly drops rep to rep.","Athlete cannot decelerate safely.","Sharp pain in calf, hip, or back."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["A-Skip","Ankling / Dribble March","Straight-Leg Bound March","Two-Point Start Walk-In"],"pairs_well_after":["Flying 10","Flying 20","Wicket Runs"],"good_for_sessions":["sprint_output","max_velocity","speed_development"],"avoid_before":["Heavy squat or RDL block","Prior max-velocity reps in same session","Fitness repeat sprints"],"avoid_after":[],"do_not_use_when":["Hamstring not warmed or prior pull this week","Athlete reports heavy legs or poor sleep","No safe deceleration space","Acute hip flexor or calf pain"]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["ALTIS Stride-Out Progressions","SimpliFaster Build-Up Sprint Coaching","Feed the Cats Speed Development"],"internal_notes":["Default Output entry before fly zones; pair with timing only when athlete is advanced."]}'::jsonb,
  updated_at = now()
WHERE slug = 'build-up-sprint-stride-out';

