  athlete_language = 'Build in smooth, then explode through the 10 — stay tall, quick, and finish the fly clean.',
  movement_family = 'Max-velocity exposure',
  primary_phase_key = 'output',
  phase_subrole = 'max_velocity_exposure',
  primary_order_slot = 'flying_sprint',
  default_sets = 1,
  default_reps = 3,
  default_work_seconds = NULL,
  default_rest_seconds = 180,
  est_seconds_per_set = 35,
  movement_requirements = '{"primary_joint_actions":["hip_extension","knee_extension","ankle_plantarflexion"],"primary_tissues":["hamstrings","glutes","calves"],"breathing_demand":"nasal","balance_demand":"dynamic","impact_level":4,"prerequisites":["build-up-sprint-stride-out"]}'::jsonb,
  coaching_execution = '{"movement_description":"15–25 yard build into 10-yard all-out fly zone with full recovery between reps.","setup":["Mark build zone (15–25 yards) and 10-yard fly zone with cones or line tape.","Optional timing gates at fly start and finish.","Confirm full recovery lane for deceleration beyond fly.","Athlete fresh — no prior max fly reps in session."],"execution_steps":["Start with rolling or three-point entry into build zone.","Build to near-max upright speed before fly start cone.","Sprint all-out through the 10-yard fly — max intent, max posture.","Maintain tall body, front-side mechanics, and stiff ankle contacts through fly.","Decelerate under control; rest full 3 minutes before next rep."],"breathing_cues":["Relaxed pre-start breath.","Do not hold breath through fly — stay loose in upper body."],"coach_cues":["Hit the fly hot.","Tall and quick.","No reaching — strike under you.","One perfect rep beats three mediocre ones.","Walk back — full rest."],"athlete_cues":["Build.","Fly.","Max intent.","Stay tall.","Finish clean."],"common_faults":["Starting all-out too early in build zone.","Not reaching fly zone at true upright speed.","Overstriding or sitting back in fly.","Cutting fly short or running extra yards for volume.","Insufficient rest turning reps into conditioning."],"stop_signs":["Fly time drops more than ~3% from best rep.","Hamstring grab or sharp posterior chain pain.","Posture breakdown every fly rep.","Athlete rushing rest to finish session faster."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Build-Up Sprint / Stride-Out","A-Skip","Straight-Leg Bound March"],"pairs_well_after":["Flying 20","Sprint-Float-Sprint","Wicket Runs"],"good_for_sessions":["sprint_output","max_velocity","speed_development"],"avoid_before":["Max-effort acceleration block same session","Heavy posterior chain lifting same day","Prior fly reps to fatigue"],"avoid_after":[],"do_not_use_when":["No build-up stride-out prerequisite met","Hamstring not prepared or prior strain","Insufficient recovery time between reps","No deceleration space after fly zone"]}'::jsonb,
