-- Sprint-Float-Sprint (sprint-float-sprint)
UPDATE coaching.exercise SET
  name = 'Sprint-Float-Sprint',
  description = 'Over a 30–40 yard rep, athlete sprints max through phase 1 (~10 yards), floats at ~85–90% through phase 2 (~10 yards), then re-accelerates to max through phase 3 (~10 yards). Mark phases with cones or line tape.',
  card_summary = 'Three-phase upright rep — max sprint, relaxed float, max sprint again — teaches speed change and rhythm at high velocity without extra fly volume.',
  coach_language = 'Use to teach re-acceleration at max velocity without adding fly rep count. Two reps with full rest — float is NOT a jog recovery.',
  athlete_language = 'Go hard, float fast but relaxed, then go hard again — stay tall through every phase.',
  movement_family = 'Max-velocity exposure',
  primary_phase_key = 'output',
  phase_subrole = 'max_velocity_exposure',
  primary_order_slot = 'speed_change',
  default_sets = 1,
  default_reps = 2,
  default_work_seconds = NULL,
  default_rest_seconds = 240,
  est_seconds_per_set = 40,
  movement_requirements = '{"primary_joint_actions":["hip_extension","knee_extension","ankle_plantarflexion"],"primary_tissues":["hamstrings","glutes","calves"],"breathing_demand":"nasal","balance_demand":"dynamic","impact_level":4,"prerequisites":["flying-10","build-up-sprint-stride-out"]}'::jsonb,
  coaching_execution = '{"movement_description":"Three-phase rep — max sprint, fast float (~85–90%), max sprint — over ~30–40 yards.","setup":["Mark three ~10-yard zones with cones or line tape.","Brief athlete on float intent — fast but relaxed, not jogging.","Rolling or fly-in entry optional based on lane length.","Full 4-minute rest between reps."],"execution_steps":["Build or start into phase 1 at max upright intent.","At phase 2 marker, float — reduce effort slightly but keep tall posture and quick feet.","At phase 3 marker, re-attack max speed immediately.","Maintain mechanics through final sprint phase.","Decelerate under control; rest full 4 minutes."],"breathing_cues":["Stay loose in float — do not hold breath through phase changes."],"coach_cues":["Float fast, not slow.","Re-attack now.","Posture stays tall in float.","Phase change is a decision, not a brake.","Two reps — quality only."],"athlete_cues":["Hard.","Float.","Hard again.","Stay tall.","No jog."],"common_faults":["Float becomes a slow jog or walk.","Posture collapse during float phase.","Cannot re-accelerate in phase 3.","Using too many reps — turns into conditioning.","Phase markers too close — no time to express each intent."],"stop_signs":["Phase 3 max speed clearly slower than phase 1.","Hamstring tightness on re-acceleration.","Athlete jogs float every rep despite coaching.","Loss of balance or control at phase transitions."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Flying 10","Build-Up Sprint / Stride-Out","Ins-and-Outs"],"pairs_well_after":["Ins-and-Outs","Wicket Runs"],"good_for_sessions":["sprint_output","max_velocity","speed_development"],"avoid_before":["Prior fly reps to fatigue","Fitness tempo runs same session"],"avoid_after":[],"do_not_use_when":["Cannot perform clean fly 10","Athlete jogs every float despite cues","Hamstring not prepared","Insufficient rest between reps"]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["ALTIS Sprint-Float-Sprint","SimpliFaster Speed Change at Max Velocity"],"internal_notes":["Coach float as ~85–90% — visually fast, slightly less aggressive arm drive."]}'::jsonb,
  updated_at = now()
WHERE slug = 'sprint-float-sprint';

