UPDATE coaching.exercise SET
  name = 'Ins-and-Outs',
  description = 'Athlete alternates between marked "in" zones (max intent) and "out" zones (fast float ~85–90%) over the length of the rep — typically 2–3 in segments. Cones or line tape define zone boundaries.',
  card_summary = 'Alternating in-zone (max) and out-zone (float) segments over 30–40 yards — rhythmic speed change at upright velocity.',
  coach_language = 'Use for rhythmic speed change — ins are max, outs are fast float. Two reps, full rest. Not a shuttle or conditioning drill.',
  athlete_language = 'When you hit the in zone, go max — in the out zone stay fast and tall but breathe a little.',
  movement_family = 'Max-velocity exposure',
  primary_phase_key = 'output',
  phase_subrole = 'max_velocity_exposure',
  primary_order_slot = 'speed_change',
  default_sets = 1,
  default_reps = 2,
  default_work_seconds = NULL,
  default_rest_seconds = 240,
  est_seconds_per_set = 40,
  movement_requirements = '{"primary_joint_actions":["hip_extension","knee_extension","ankle_plantarflexion"],"primary_tissues":["hamstrings","glutes","calves"],"breathing_demand":"nasal","balance_demand":"dynamic","impact_level":4,"prerequisites":["sprint-float-sprint","flying-10"]}'::jsonb,
  coaching_execution = '{"movement_description":"Alternating max \"in\" zones and fast-float \"out\" zones over 30–40 yards.","setup":["Mark 2–3 in zones (~10 yards) and out zones (~5–10 yards) with cones or tape.","Define verbal or visual cue for in/out transitions.","Fly-in or build entry to reach upright speed before first in zone.","4-minute rest between reps."],"execution_steps":["Build to upright speed approaching first in zone.","Sprint max through each in zone — full intent, tall posture.","Float fast but relaxed through each out zone — no jogging.","Re-attack max immediately at next in zone marker.","Decelerate after final in zone; rest fully before next rep."],"breathing_cues":["Slightly easier breathing in out zones — never stop moving fast."],"coach_cues":["In — go!","Out — stay fast.","In — max again.","No jog in the outs.","Two reps, then done."],"athlete_cues":["In hard.","Out fast.","In hard.","Stay tall.","Finish clean."],"common_faults":["Out zones become slow jogs.","Missing in zone markers — starting max too early or late.","Too many segments turning rep into conditioning.","Posture drop in later in zones.","Using ins-and-outs before fly 10 quality exists."],"stop_signs":["Later in zones clearly slower than first.","Athlete cannot maintain float faster than jog pace.","Hamstring symptoms on re-acceleration.","Dizziness or loss of control at transitions."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Sprint-Float-Sprint","Flying 10","Build-Up Sprint / Stride-Out"],"pairs_well_after":["Wicket Runs","Curved Sprint / Arc Run"],"good_for_sessions":["sprint_output","max_velocity","speed_development"],"avoid_before":["Sprint-float-sprint to fatigue in same session","Team relay or shuttle conditioning"],"avoid_after":[],"do_not_use_when":["Sprint-float-sprint prerequisite not met","Athlete jogs all out zones","Hamstring not prepared","Insufficient lane length for marked zones"]}'::jsonb,
