  card_summary = 'Upright sprint through spaced wickets (mini gates) that constrain stride length and encourage optimal cadence at near-max velocity.',
  coach_language = 'Use wickets to organize stride frequency at high speed. Three runs with 2-minute rest — spacing must match athlete; do not chase wicket contact at all costs.',
  athlete_language = 'Sprint tall through the gates — quick feet, strike under you, and let the wickets guide your rhythm.',
  movement_family = 'Max-velocity exposure',
  primary_phase_key = 'output',
  phase_subrole = 'max_velocity_exposure',
  primary_order_slot = 'wicket_rhythm',
  default_sets = 1,
  default_reps = 3,
  default_work_seconds = NULL,
