  coaching_execution = '{"movement_description":"Near-max upright sprint through wicket lane — cadence and foot strike guided by gate spacing.","setup":["Set wickets or cone gates for athlete height/speed (often ~1.5–1.8m spacing to start — adjust individually).","10–20 yard build before wicket zone optional.","6–10 wickets typical for one run.","2-minute rest between runs."],"execution_steps":["Build to near-max speed entering wicket lane.","Sprint upright through wickets — strike under body, not reaching for gates.","Maintain tall posture and quick cadence; wickets guide rhythm.","Do not stutter or hop to hit every gate — adjust spacing if needed.","Decelerate after final wicket; walk back and rest."],"breathing_cues":["Stay relaxed through upper body while legs turn over quickly."],"coach_cues":["Strike under you.","Let wickets come to you.","Tall and quick.","Fix spacing, not the athlete''s jump.","Three clean runs."],"athlete_cues":["Quick feet.","Tall.","Through the gates.","Rhythm.","Stay smooth."],"common_faults":["Wicket spacing too wide — overstriding returns.","Spacing too tight — stutter steps or hopping.","Treating wickets like hurdles to clear.","Submax effort through wickets — should be near-max when prescribed.","Too many runs when cadence degrades."],"stop_signs":["Stutter-stepping every run despite spacing adjustment.","Ankle or shin pain from awkward contacts.","Athlete cannot maintain upright posture through lane.","Cadence slows run to run."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Flying 10","Build-Up Sprint / Stride-Out","A-Skip"],"pairs_well_after":["Mini-Hurdle Sprint Rhythm","Flying 10","Curved Sprint / Arc Run"],"good_for_sessions":["sprint_output","max_velocity","speed_development"],"avoid_before":["Ankling to shin fatigue","Mini-hurdle rhythm to failure same session"],"avoid_after":[],"do_not_use_when":["No wickets or suitable cone gates available","Spacing cannot be adjusted for athlete","Athlete stutter-steps every attempt","Acute shin or ankle pain"]}'::jsonb,
