-- Mini-Hurdle Sprint Rhythm (mini-hurdle-sprint-rhythm)
UPDATE coaching.exercise SET
  name = 'Mini-Hurdle Sprint Rhythm',
  description = 'Athlete sprints through a lane of low mini-hurdles (typically 6–12 inches) spaced for quick turnover at near-max upright speed. Hurdles are run through, not jumped — emphasis on rhythm, dorsiflexion, and foot strike under the hip.',
  card_summary = 'Low mini-hurdle sprint rhythm drill that enforces quick cadence and upright foot strike at high speed — distinct from wicket gate spacing.',
  coach_language = 'Use mini-hurdles for cadence and dorsiflexion at speed — not plyometric hurdle hops. Three runs, 90-second rest; lower hurdles than you think.',
  athlete_language = 'Run through the hurdles quick and tall — toe up, light feet, don''t jump them.',
  movement_family = 'Max-velocity exposure',
  primary_phase_key = 'output',
  phase_subrole = 'max_velocity_exposure',
  primary_order_slot = 'wicket_rhythm',
  default_sets = 1,
  default_reps = 3,
  default_work_seconds = NULL,
  default_rest_seconds = 90,
  est_seconds_per_set = 25,
  movement_requirements = '{"primary_joint_actions":["hip_flexion","ankle_dorsiflexion","ankle_plantarflexion"],"primary_tissues":["calves","hip_flexors","feet"],"breathing_demand":"nasal","balance_demand":"dynamic","impact_level":4,"prerequisites":["wicket-runs","a-skip"]}'::jsonb,
  coaching_execution = '{"movement_description":"Near-max sprint through low mini-hurdle lane — run through, do not jump.","setup":["Set 6–8 low mini-hurdles (6–12 inches) with spacing for athlete cadence.","Optional 10-yard build before hurdle lane.","Confirm hurdles will tip if clipped — safety first.","90-second rest between runs."],"execution_steps":["Build to near-max upright speed entering hurdle lane.","Run through hurdles with quick cadence — toes up, light contacts.","Do not jump or bound over hurdles — stride through them.","Maintain tall posture and arm action through lane.","Decelerate after final hurdle; rest fully."],"breathing_cues":["Stay loose — quick feet should not mean held breath."],"coach_cues":["Run through, not over.","Toe up.","Quick and tall.","Lower the hurdle before widening spacing.","Three runs — stop if you start jumping."],"athlete_cues":["Quick feet.","Through not over.","Toe up.","Tall.","Light steps."],"common_faults":["Hurdles set too high — athlete jumps.","Spacing too wide — overstriding returns.","Spacing too tight — stutter or shuffle.","Using plyometric hop intent instead of sprint rhythm.","Too many runs when form becomes hop-dominant."],"stop_signs":["Athlete jumps every hurdle.","Shin or ankle pain from clipping hurdles.","Stutter-stepping through lane.","Cadence slows significantly run to run."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Wicket Runs","A-Skip","Ankling / Dribble March","Flying 10"],"pairs_well_after":["Flying 10","Curved Sprint / Arc Run"],"good_for_sessions":["sprint_output","max_velocity","speed_development"],"avoid_before":["Hurdle hop plyometric series same session","Shin-fatiguing ankling volume"],"avoid_after":[],"do_not_use_when":["No low mini-hurdles available","Athlete jumps hurdles instead of running through","Acute shin or ankle pain","Hurdles fixed too high to tip safely"]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["Chris Parno Mini-Hurdle Sprint Rhythm","SimpliFaster Low Hurdle Cadence Drills","ALTIS Rhythm Hurdle Series"],"internal_notes":["Keep hurdles lower than plyometric hurdle hops — different slot and intent."]}'::jsonb,
  updated_at = now()
WHERE slug = 'mini-hurdle-sprint-rhythm';

