-- Curved Sprint / Arc Run (curved-sprint-arc-run)
UPDATE coaching.exercise SET
  name = 'Curved Sprint / Arc Run',
  description = 'Athlete sprints at high intent along a marked curved path (arc run) — typically on a grass field line, cone arc, or lane tape curve with a radius appropriate for the athlete. Maintains upright posture while managing centripetal force and arm action on the curve.',
  card_summary = 'High-speed sprint on a gentle arc or curved path — exposes max velocity with lateral force and posture demands distinct from straight-line fly work.',
  coach_language = 'Use for curved max-speed exposure after straight-line work. Three reps with 90-second rest — gentle radius for beginners; do not curve at max speed on tight circles early.',
  athlete_language = 'Sprint the arc tall — lean into the curve with your whole body, quick feet, and stay smooth.',
  movement_family = 'Max-velocity exposure',
  primary_phase_key = 'output',
  phase_subrole = 'max_velocity_exposure',
  primary_order_slot = 'curved_sprint',
  default_sets = 1,
  default_reps = 3,
  default_work_seconds = NULL,
  default_rest_seconds = 90,
  est_seconds_per_set = 30,
  movement_requirements = '{"primary_joint_actions":["hip_extension","ankle_plantarflexion","hip_adduction"],"primary_tissues":["glutes","calves","hip_stabilizers"],"breathing_demand":"nasal","balance_demand":"dynamic","impact_level":4,"prerequisites":["flying-10","build-up-sprint-stride-out"]}'::jsonb,
  coaching_execution = '{"movement_description":"High-intent sprint along marked gentle arc — upright posture with appropriate curve lean.","setup":["Mark arc with cones or line tape on grass or track curve.","Choose wide radius for beginners (e.g. 15–20+ meters); tighten only with experience.","Define arc length (~20–30 yards along curve).","90-second rest between reps; alternate directions if prescribed."],"execution_steps":["Build or fly-in to high speed entering arc.","Lean into curve with whole body — not just at ankles.","Maintain quick cadence and foot strike under hip on curve.","Keep eyes up and posture tall through arc exit.","Decelerate safely after arc; rest fully."],"breathing_cues":["Stay relaxed through shoulders on curve — tension slows cadence."],"coach_cues":["Lean the body, not just the ankles.","Quick feet on the curve.","Wide arc first.","Tall through exit.","Three reps each direction max."],"athlete_cues":["Smooth arc.","Lean in.","Quick feet.","Tall exit.","Stay controlled."],"common_faults":["Radius too tight — stutter or brake every step.","Leaning only at ankles instead of whole body.","Slowing to jog through curve.","Using curved sprint before straight fly quality exists.","Too many reps on same-direction curve loading inside leg."],"stop_signs":["Ankle or knee pain on inside/outside leg of curve.","Loss of control or stumbling on arc.","Athlete cannot maintain speed through curve.","Hip or groin symptoms on repeated same-direction reps."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Flying 10","Wicket Runs","Build-Up Sprint / Stride-Out"],"pairs_well_after":["Curved Run to Cut","Reactive Gate Sprint"],"good_for_sessions":["sprint_output","max_velocity","speed_development"],"avoid_before":["Tight COD reps to fatigue before arc sprint","Straight fly reps to exhaustion same session"],"avoid_after":[],"do_not_use_when":["Straight-line fly 10 not yet clean","No space for safe wide arc","Ankle, knee, or groin pain on lateral loading","Wet or uneven surface on curve"]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["ALTIS Curved Sprint Progressions","SimpliFaster Arc Run Coaching","Feed the Cats Curve Sprinting"],"internal_notes":["Alternate curve direction across reps to manage lateral asymmetry."]}'::jsonb,
  updated_at = now()
WHERE slug = 'curved-sprint-arc-run';

