  ('flying-20', 'Generally avoid true max-velocity sprinting unless cleared and symptom-free. Prefer build-up stride-outs at moderate intent with extra recovery.', 'No default male/female dosage split. Scale by sprint training age, max-velocity tolerance, hamstring readiness, symptoms, and prior session load.'),
  ('sprint-float-sprint', 'Generally avoid true max-velocity sprinting unless cleared and symptom-free. Prefer build-up stride-outs at moderate intent with extra recovery.', 'No default male/female dosage split. Scale by sprint training age, max-velocity tolerance, hamstring readiness, symptoms, and prior session load.'),
  ('ins-and-outs', 'Generally avoid true max-velocity sprinting unless cleared and symptom-free. Prefer build-up stride-outs at moderate intent with extra recovery.', 'No default male/female dosage split. Scale by sprint training age, max-velocity tolerance, hamstring readiness, symptoms, and prior session load.'),
  ('wicket-runs', 'Generally avoid true max-velocity sprinting unless cleared and symptom-free. Prefer build-up stride-outs at moderate intent with extra recovery.', 'No default male/female dosage split. Scale by sprint training age, max-velocity tolerance, hamstring readiness, symptoms, and prior session load.'),
  ('mini-hurdle-sprint-rhythm', 'Generally avoid high-speed hurdle rhythm unless cleared; prefer wicket runs at submax.', 'No default male/female dosage split. Scale by sprint training age, max-velocity tolerance, hamstring readiness, symptoms, and prior session load.'),
  ('curved-sprint-arc-run', 'Avoid high-speed curved sprinting unless cleared; prefer straight submax work.', 'No default male/female dosage split. Scale by sprint training age, max-velocity tolerance, hamstring readiness, symptoms, and prior session load.')
) AS v(slug, guidance, gender_notes)
JOIN coaching.exercise e ON e.slug = v.slug
WHERE sp.exercise_id = e.id AND sp.cohort_key = 'pregnancy_postpartum';

INSERT INTO coaching.exercise_scaling_profile (exercise_id, cohort_key, label, scale_direction, load_guidance, gender_specific_notes)
SELECT e.id, 'pregnancy_postpartum', 'pregnancy postpartum', 'baseline', v.guidance,
  CASE WHEN 'pregnancy_postpartum' = 'adult_beginner' THEN v.gender_notes ELSE NULL END
FROM (VALUES
  ('build-up-sprint-stride-out', 'Submax stride-outs at moderate intent only if cleared; skip true max effort.', 'No default male/female dosage split. Scale by sprint training age, max-velocity tolerance, hamstring readiness, symptoms, and prior session load.'),
  ('flying-10', 'Generally avoid true max-velocity sprinting unless cleared and symptom-free. Prefer build-up stride-outs at moderate intent with extra recovery.', 'No default male/female dosage split. Scale by sprint training age, max-velocity tolerance, hamstring readiness, symptoms, and prior session load.'),
  ('flying-20', 'Generally avoid true max-velocity sprinting unless cleared and symptom-free. Prefer build-up stride-outs at moderate intent with extra recovery.', 'No default male/female dosage split. Scale by sprint training age, max-velocity tolerance, hamstring readiness, symptoms, and prior session load.'),
  ('sprint-float-sprint', 'Generally avoid true max-velocity sprinting unless cleared and symptom-free. Prefer build-up stride-outs at moderate intent with extra recovery.', 'No default male/female dosage split. Scale by sprint training age, max-velocity tolerance, hamstring readiness, symptoms, and prior session load.'),
  ('ins-and-outs', 'Generally avoid true max-velocity sprinting unless cleared and symptom-free. Prefer build-up stride-outs at moderate intent with extra recovery.', 'No default male/female dosage split. Scale by sprint training age, max-velocity tolerance, hamstring readiness, symptoms, and prior session load.'),
  ('wicket-runs', 'Generally avoid true max-velocity sprinting unless cleared and symptom-free. Prefer build-up stride-outs at moderate intent with extra recovery.', 'No default male/female dosage split. Scale by sprint training age, max-velocity tolerance, hamstring readiness, symptoms, and prior session load.'),
  ('mini-hurdle-sprint-rhythm', 'Generally avoid high-speed hurdle rhythm unless cleared; prefer wicket runs at submax.', 'No default male/female dosage split. Scale by sprint training age, max-velocity tolerance, hamstring readiness, symptoms, and prior session load.'),
  ('curved-sprint-arc-run', 'Avoid high-speed curved sprinting unless cleared; prefer straight submax work.', 'No default male/female dosage split. Scale by sprint training age, max-velocity tolerance, hamstring readiness, symptoms, and prior session load.')
) AS v(slug, guidance, gender_notes)
JOIN coaching.exercise e ON e.slug = v.slug
WHERE NOT EXISTS (
