  WHERE sp.exercise_id = e.id AND sp.cohort_key = 'pregnancy_postpartum'
);

-- Why-layer education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_works, why_it_matters, why_it_goes_here,
  programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name, e.card_summary,
  e.description,
  v.why_works,
  'Develops tagged tenets and physiological qualities for athletic development.',
  v.why_here,
  v.best_placement,
  v.misuse,
  v.scale_guidance
FROM (VALUES
  ('build-up-sprint-stride-out', 'Build-up stride-outs let the athlete find max upright velocity through a controlled acceleration curve rather than jumping straight to fly zones. Coaches can observe posture rise, foot strike, and arm action while neural demand stays manageable relative to shorter all-out fly reps.', 'Belongs in sprint_exposure (321) — first upright speed expression in Max-Velocity Exposure before flying sprints or rhythm constraints.', 'First max-velocity exposure drill in the block after Skill prep and optional short acceleration work; before flying sprints or speed-change reps.', 'Max-velocity exposure belongs in Output while the athlete is fresh — express upright speed with full recovery between reps. Do not use as a conditioning finisher, repeated tempo runs, warm-up jog, or volume work when speed or posture drops. Quality and neural freshness beat rep count. Do not turn into 10×100 tempo runs or a warm-up lap. One to three crisp reps with full rest.', 'Regress to shorter distance or submax stride-outs; progress to flying 10 once build-up mechanics and decel are consistently clean.'),
  ('flying-10', 'The fly zone isolates upright max velocity without the acceleration noise of the first steps. A 10-yard fly is long enough to express top speed yet short enough to preserve quality and allow full recovery between reps.', 'Belongs in flying_sprint (322) — standard fly-in max-velocity rep after sprint exposure prep.', 'After build-up stride-out when athlete can reach upright posture before the fly zone; early in max-velocity block.', 'Max-velocity exposure belongs in Output while the athlete is fresh — express upright speed with full recovery between reps. Do not use as a conditioning finisher, repeated tempo runs, warm-up jog, or volume work when speed or posture drops. Quality and neural freshness beat rep count. Do not stack 8–10 fly reps or use as a finisher. Two to three reps with 3+ minutes rest.', 'Regress to build-up stride-out or shorten build zone; add timing gates only when mechanics are consistent.'),
  ('flying-20', 'A 20-yard fly extends time at true max velocity, challenging hamstring tolerance and upright posture maintenance longer than fly 10. Useful for field-sport athletes who must sustain top speed briefly — but only when fly 10 quality is already established.', 'Belongs in flying_sprint (322) — advanced fly exposure after fly 10, not a beginner max-velocity entry.', 'After flying 10 when athlete shows clean upright mechanics and needs longer speed endurance at max velocity — not before fly 10 mastery.', 'Max-velocity exposure belongs in Output while the athlete is fresh — express upright speed with full recovery between reps. Do not use as a conditioning finisher, repeated tempo runs, warm-up jog, or volume work when speed or posture drops. Quality and neural freshness beat rep count. Do not assign fly 20 before fly 10 is clean. Two reps max for most athletes — not a volume progression.', 'Regress to flying 10; shorten fly zone to 15 yards for intermediate athletes before full 20-yard fly.'),
  ('sprint-float-sprint', 'Sprint-float-sprint challenges the athlete to downshift speed slightly without losing posture, then re-attack max velocity — a field-sport pattern. It adds neural complexity beyond steady fly reps while keeping total high-speed distance modest.', 'Belongs in speed_change (323) — rhythm and re-acceleration at max velocity, not steady fly exposure.', 'After fly 10 when athlete can hold upright speed and needs speed-change exposure; mid max-velocity block.', 'Max-velocity exposure belongs in Output while the athlete is fresh — express upright speed with full recovery between reps. Do not use as a conditioning finisher, repeated tempo runs, warm-up jog, or volume work when speed or posture drops. Quality and neural freshness beat rep count. Float is not a slow jog or walk — maintain fast upright mechanics. Do not use as a conditioning pyramid.', 'Regress to build-up stride-out; shorten phases or use submax intent in float before full sprint-float-sprint.'),
  ('ins-and-outs', 'Ins-and-outs repeat the speed-change demand across multiple segments, training the athlete to toggle max intent on cue while maintaining upright mechanics in float segments — useful for sports with variable sprint demands.', 'Belongs in speed_change (323) — segmented rhythm alternative to sprint-float-sprint.', 'After sprint-float-sprint or fly 10 when athlete needs segmented speed-change rhythm; alternate with sprint-float-sprint across mesocycle.', 'Max-velocity exposure belongs in Output while the athlete is fresh — express upright speed with full recovery between reps. Do not use as a conditioning finisher, repeated tempo runs, warm-up jog, or volume work when speed or posture drops. Quality and neural freshness beat rep count. Out zones are not recovery jogs. Do not add extra segments for volume or use as a team conditioning relay.', 'Start with two in/out cycles at submax; shorten zones before adding a third in segment.'),
  ('wicket-runs', 'Wickets provide external rhythm cues that encourage optimal stride length and cadence at high velocity without coach constantly shouting "quicker feet." Athletes who overstride at max speed often self-correct when wicket spacing demands shorter, faster contacts.', 'Belongs in wicket_rhythm (324) — upright rhythm constraint at max velocity using wicket spacing.', 'After fly 10 or build-up when athlete needs rhythm constraint at high speed; pairs well before or after straight fly work.', 'Max-velocity exposure belongs in Output while the athlete is fresh — express upright speed with full recovery between reps. Do not use as a conditioning finisher, repeated tempo runs, warm-up jog, or volume work when speed or posture drops. Quality and neural freshness beat rep count. Wickets are not mini-hurdles to jump over. Do not use wrong spacing that forces bounding or stutter steps.', 'Adjust wicket spacing to athlete height and speed; regress to submax run-throughs before max intent.'),
  ('mini-hurdle-sprint-rhythm', 'Mini-hurdles add a visible rhythm target that encourages shorter, quicker strides and dorsiflexed foot strike at high speed. The low height keeps the drill sprint-specific rather than becoming a bounding or hop series.', 'Belongs in wicket_rhythm (324) — hurdle-based rhythm constraint complement to wicket runs.', 'After wicket runs or A-skip when athlete needs low hurdle rhythm constraint; alternate with wicket runs across mesocycle.', 'Max-velocity exposure belongs in Output while the athlete is fresh — express upright speed with full recovery between reps. Do not use as a conditioning finisher, repeated tempo runs, warm-up jog, or volume work when speed or posture drops. Quality and neural freshness beat rep count. Hurdles too high or too far apart turn this into bounding or plyometrics. Do not use as a hop conditioning circuit.', 'Lower hurdle height and tighten spacing before adding speed; regress to wicket runs if athlete jumps hurdles.'),
  ('curved-sprint-arc-run', 'Curved sprinting adds lateral force and whole-body lean demands that straight fly reps do not address — relevant for field sports with arc running patterns. Gentle arcs at high speed train posture and foot strike under centripetal load.', 'Belongs in curved_sprint (325) — arc max-velocity exposure after straight-line fly and rhythm work.', 'Late in max-velocity block when straight-line fly quality is established; sport-specific curved running exposure.', 'Max-velocity exposure belongs in Output while the athlete is fresh — express upright speed with full recovery between reps. Do not use as a conditioning finisher, repeated tempo runs, warm-up jog, or volume work when speed or posture drops. Quality and neural freshness beat rep count. Do not use tight circle sprints as a conditioning finisher. Wide radius, high intent, low rep count.', 'Widen arc radius or reduce speed before tightening curve; regress to straight fly 10 if posture breaks on arc.')
) AS v(slug, why_works, why_here, best_placement, misuse, scale_guidance)
JOIN coaching.exercise e ON e.slug = v.slug
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
  title = EXCLUDED.title,
  short_summary = EXCLUDED.short_summary,
  what_it_is = EXCLUDED.what_it_is,
  why_it_works = EXCLUDED.why_it_works,
  why_it_goes_here = EXCLUDED.why_it_goes_here,
  programming_guidance = EXCLUDED.programming_guidance,
  common_misuse = EXCLUDED.common_misuse,
  scaling_guidance = EXCLUDED.scaling_guidance,
  updated_at = now();

-- Max-velocity cluster validation education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_matters, programming_guidance, common_misuse
)
VALUES (
  'validation_rule',
  'output_max_velocity_readiness',
  NULL,
  'Max-Velocity Exposure without pre-fatigue',
  'Max-velocity sprinting requires freshness, full rest, short reps, and crisp mechanics — not conditioning circuits, finishers, or warm-up jogs.',
  'Output max-velocity cards express upright sprint speed through build-ups, flying sprints, speed-change drills, wicket rhythm, and curved sprinting.',
  'High-speed sprinting loads hamstrings, calves, Achilles, and neural systems heavily. Poor placement, short rest, or excessive volume turns Output into speed endurance and raises injury risk.',
  'Use Build-Up Sprint first for beginners, Flying 10 before Flying 20, 2+ minute rest on fly sprints, stop when speed or posture drops, and place max-velocity work before Capacity and Fitness.',
  'Do not program max-velocity sprints after conditioning, with short rest, as session finishers, or at volumes that drop speed — regress dose or change phase intent.'
)
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
  title = EXCLUDED.title,
  short_summary = EXCLUDED.short_summary,
  what_it_is = EXCLUDED.what_it_is,
  why_it_matters = EXCLUDED.why_it_matters,
  programming_guidance = EXCLUDED.programming_guidance,
  common_misuse = EXCLUDED.common_misuse,
  updated_at = now();
